// Extract email body, subject, and arrival timestamp.
// With the Gmail Trigger's "Simplify" option ON (the default), n8n only returns
// a short `snippet` preview — never the full body — which silently truncates the
// email before the STRUCTURED DATA section. So this reads the raw Gmail API
// message resource (returned when Simplify is OFF) directly: walk payload.parts
// for a text/plain part (falling back to text/html), base64url-decode it, and
// only fall back to the simplified fields/snippet if no raw payload is present.
const msg = items[0].json;
const subject = (msg.payload?.headers || []).find(h => h.name === 'Subject')?.value || msg.subject || '';
const arrivalTs = msg.internalDate ? new Date(Number(msg.internalDate)).toISOString() : (msg.date || new Date().toISOString());

function b64urlDecode(data) {
  if (!data) return '';
  return Buffer.from(data.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8');
}

function findPart(payload, mimeType) {
  if (!payload) return null;
  if (payload.mimeType === mimeType && payload.body?.data) return payload.body.data;
  for (const part of payload.parts || []) {
    const found = findPart(part, mimeType);
    if (found) return found;
  }
  return null;
}

let body = '';
if (msg.payload) {
  const plainData = findPart(msg.payload, 'text/plain');
  if (plainData) {
    body = b64urlDecode(plainData);
  } else {
    const htmlData = findPart(msg.payload, 'text/html');
    if (htmlData) body = b64urlDecode(htmlData).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  }
}

// Fallbacks for n8n's simplified-mode field names, in case Simplify stays ON.
if (!body && msg.text) body = msg.text;
else if (!body && msg.textHtml) body = msg.textHtml.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
else if (!body && msg.html) body = msg.html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
else if (!body && msg.snippet) body = msg.snippet;

if (!body || body.trim().length < 50) {
  throw new Error(`PARSE_FAIL: Email body too short or empty. Subject: ${subject}, Arrival: ${arrivalTs}`);
}

return [{ json: { body, subject, arrivalTs } }];

// Extract the fenced ```json STRUCTURED DATA block ChatGPT emits directly in the
// email (see the scheduled prompt), and JSON.parse it. No AI call anywhere in this
// workflow — ChatGPT already produces schema-shaped JSON upstream.
// Keep this logic in sync with assets/js/lib/extract-json.js (n8n Function nodes
// cannot `import` repo files, so this is a byte-equivalent inline copy).
const { body, subject, arrivalTs } = items[0].json;

function extractFirstBalancedObject(text) {
  const start = text.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escaped = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escaped) escaped = false;
      else if (ch === '\\') escaped = true;
      else if (ch === '"') inString = false;
      continue;
    }
    if (ch === '"') { inString = true; continue; }
    if (ch === '{') depth++;
    else if (ch === '}') { depth--; if (depth === 0) return text.slice(start, i + 1); }
  }
  return null;
}

// Mail transfer agents / plain-text rendering commonly hard-wrap long lines,
// which can inject a raw newline in the middle of a JSON string value — JSON.parse
// rejects that as a bad control character. Collapse it to a space instead of failing.
function sanitizeStringNewlines(text) {
  let result = '';
  let inString = false, escaped = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escaped) { escaped = false; result += ch; continue; }
      if (ch === '\\') { escaped = true; result += ch; continue; }
      if (ch === '"') { inString = false; result += ch; continue; }
      result += (ch === '\n' || ch === '\r') ? ' ' : ch;
      continue;
    }
    if (ch === '"') inString = true;
    result += ch;
  }
  return result;
}

function extractJsonBlock(rawText) {
  if (typeof rawText !== 'string') return null;
  const fenced = rawText.match(/```json\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1].trim() : extractFirstBalancedObject(rawText);
  return candidate === null ? null : sanitizeStringNewlines(candidate);
}

const jsonText = extractJsonBlock(body);
if (!jsonText) {
  return [{ json: { valid: false, error: 'PARSE_FAIL', message: 'No JSON block found in email body', subject, arrivalTs } }];
}

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  return [{ json: { valid: false, error: 'PARSE_FAIL', message: e.message, subject, arrivalTs } }];
}

return [{ json: { parsed, subject, arrivalTs } }];

// Validate the extracted briefing against the Per-Day JSON Schema (v1 + v2 fields).
// Keep the structural checks here in sync with assets/js/lib/schema.js's
// validateBriefing/normalizeBriefing (n8n Function nodes cannot import that file).
const input = items[0].json;
const { subject, arrivalTs } = input;

// Pass through an upstream extraction failure unchanged.
if (input.valid === false) return [{ json: input }];

const parsed = input.parsed;
const { meta, summary, triggers, deep_dive, outlook, prediction_result } = parsed || {};

if (!meta?.date || !/^\d{4}-\d{2}-\d{2}$/.test(meta.date)) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'meta.date missing or invalid', subject, arrivalTs } }];
}
if (!['Trading','Holiday'].includes(meta.session_status)) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'meta.session_status invalid', subject, arrivalTs } }];
}
if (!summary || !triggers || !deep_dive || !outlook || !prediction_result) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'Missing top-level keys', subject, arrivalTs } }];
}
if (!Array.isArray(outlook.scenarios) || outlook.scenarios.length < 1 || outlook.scenarios.length > 5) {
  return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: 'outlook.scenarios must be 1-5 items', subject, arrivalTs } }];
}
for (const s of outlook.scenarios) {
  if (s.probability < 0 || s.probability > 100) {
    return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: `scenario probability out of range: ${s.probability}`, subject, arrivalTs } }];
  }
  if (s.range_low > s.range_high) {
    return [{ json: { valid: false, error: 'SCHEMA_FAIL', message: `range_low > range_high in scenario: ${s.name}`, subject, arrivalTs } }];
  }
}

// Default v1+v2 fields to null/[] if ChatGPT ever omits them, mirroring normalizeBriefing,
// so nothing downstream (merge, site rendering) ever sees an undefined key.
meta.sources = Array.isArray(meta.sources) ? meta.sources : [];
summary.sectors = summary.sectors || {};
summary.sectors.leaders = Array.isArray(summary.sectors.leaders) ? summary.sectors.leaders : [];
summary.sectors.laggards = Array.isArray(summary.sectors.laggards) ? summary.sectors.laggards : [];
summary.key_gainers = Array.isArray(summary.key_gainers) ? summary.key_gainers : [];
summary.key_losers = Array.isArray(summary.key_losers) ? summary.key_losers : [];
summary.macro = summary.macro || {};
for (const k of ['brent_crude', 'india_10y_yield', 'usd_inr', 'gold', 'india_vix', 'us_10y_yield']) {
  if (summary.macro[k] === undefined) summary.macro[k] = null;
}
summary.global_indices = Array.isArray(summary.global_indices) ? summary.global_indices : [];
triggers.domestic = Array.isArray(triggers.domestic) ? triggers.domestic : [];
triggers.global = Array.isArray(triggers.global) ? triggers.global : [];
deep_dive.summary_takeaway = deep_dive.summary_takeaway === undefined ? null : deep_dive.summary_takeaway;
outlook.support_levels = Array.isArray(outlook.support_levels) ? outlook.support_levels : [];
outlook.resistance_levels = Array.isArray(outlook.resistance_levels) ? outlook.resistance_levels : [];
outlook.key_watch = Array.isArray(outlook.key_watch) ? outlook.key_watch : [];

return [{ json: { valid: true, briefing: parsed, date: meta.date, subject, arrivalTs } }];

// --- resilient GitHub-helper accessors (n8n sandbox quirks; see below) ---
// httpRequest: $helpers.httpRequest can be undefined/unbound on some n8n builds
// (a long-standing sandbox bug). this.helpers.httpRequest is the reliable form,
// so prefer it and only fall back to $helpers.httpRequest.
const httpRequest = (this && this.helpers && this.helpers.httpRequest)
  ? this.helpers.httpRequest.bind(this.helpers)
  : $helpers.httpRequest;
// Token: $env is the reliable accessor for env vars inside the Code/Function
// sandbox; process.env is blocked (returns undefined) on n8n Cloud and when
// N8N_BLOCK_ENV_ACCESS_IN_NODE is set. Read via $env, fall back to process.env.
const GITHUB_TOKEN = (typeof $env !== 'undefined' && $env.GITHUB_TOKEN)
  ? $env.GITHUB_TOKEN
  : process.env.GITHUB_TOKEN;

// Check whether data/briefings/{date}.json already exists — drives the merge
// step next, so a duplicate/repeat email never overwrites data already captured
// (including a prediction_result the Prediction_Tracker workflow may have written).
const { date } = items[0].json;

// NOTE: never let a raw error from $helpers.httpRequest (or any library call)
// escape this function uncaught. n8n's legacy Function node has a bug in its own
// error formatter (Function.node.ts) that crashes with "Cannot read properties
// of undefined (reading 'split')" whenever the real error's stack trace doesn't
// contain the literal word "Function" — which hides the actual failure. Always
// catch and re-throw a fresh `new Error(...)` built right here instead, so a
// normal, readable message and stack always reach n8n's execution log.
function isNotFoundError(e) {
  const code = e?.httpCode ?? e?.statusCode ?? e?.response?.status ?? e?.response?.statusCode ?? e?.cause?.response?.status;
  return String(code) === '404';
}
function asObject(res) {
  return typeof res === 'string' ? JSON.parse(res) : res;
}

let existing = null;
let sha = null;
try {
  const raw = await httpRequest({
    method: 'GET',
    url: `https://api.github.com/repos/bmdeshmukh18/briefing/contents/data/briefings/${date}.json`,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github.v3+json'
    },
    json: true
  });
  const res = asObject(raw);
  sha = res.sha;
  existing = JSON.parse(Buffer.from(res.content, 'base64').toString());
} catch (e) {
  if (!isNotFoundError(e)) throw new Error(`GitHub GET failed for data/briefings/${date}.json: ${e?.message || e}`);
}

return [{ json: { ...items[0].json, existing, sha } }];

// Fill-only-nulls merge: keep every already-present field in 'existing' as-is,
// only fill fields that are null/empty there from 'incoming'. Never touches
// prediction_result (owned exclusively by the Prediction_Tracker workflow).
// Keep this logic in sync with assets/js/lib/core.js's mergeBriefing.
const { briefing: incoming, existing, sha, date } = items[0].json;

function isEmptyValue(v) {
  return v === null || v === undefined || (Array.isArray(v) && v.length === 0);
}
function mergeScalar(e, i) {
  return isEmptyValue(e) && !isEmptyValue(i) ? i : e;
}
function mergeField(eo, io, key) {
  return mergeScalar(eo?.[key], io?.[key]);
}
function mergeBriefing(e, i) {
  if (!e) return i;
  if (!i) return e;
  return {
    meta: {
      date: e.meta?.date ?? i.meta?.date ?? null,
      session_status: e.meta?.session_status ?? i.meta?.session_status ?? null,
      market_tone: mergeField(e.meta, i.meta, 'market_tone'),
      sources: mergeScalar(e.meta?.sources, i.meta?.sources) ?? [],
    },
    summary: {
      nifty50: { close: mergeField(e.summary?.nifty50, i.summary?.nifty50, 'close'), change_pct: mergeField(e.summary?.nifty50, i.summary?.nifty50, 'change_pct') },
      sensex: { close: mergeField(e.summary?.sensex, i.summary?.sensex, 'close'), change_pct: mergeField(e.summary?.sensex, i.summary?.sensex, 'change_pct') },
      broader_market: { smallcap_pct: mergeField(e.summary?.broader_market, i.summary?.broader_market, 'smallcap_pct'), midcap_pct: mergeField(e.summary?.broader_market, i.summary?.broader_market, 'midcap_pct') },
      breadth: { nifty500_advances: mergeField(e.summary?.breadth, i.summary?.breadth, 'nifty500_advances'), nifty500_declines: mergeField(e.summary?.breadth, i.summary?.breadth, 'nifty500_declines') },
      sectors: {
        leaders: mergeScalar(e.summary?.sectors?.leaders, i.summary?.sectors?.leaders) ?? [],
        laggards: mergeScalar(e.summary?.sectors?.laggards, i.summary?.sectors?.laggards) ?? [],
        count_advanced: mergeField(e.summary?.sectors, i.summary?.sectors, 'count_advanced'),
      },
      key_gainers: mergeScalar(e.summary?.key_gainers, i.summary?.key_gainers) ?? [],
      key_losers: mergeScalar(e.summary?.key_losers, i.summary?.key_losers) ?? [],
      institutional_flows: { fii_net_cr: mergeField(e.summary?.institutional_flows, i.summary?.institutional_flows, 'fii_net_cr'), dii_net_cr: mergeField(e.summary?.institutional_flows, i.summary?.institutional_flows, 'dii_net_cr') },
      macro: {
        brent_crude: mergeField(e.summary?.macro, i.summary?.macro, 'brent_crude'),
        india_10y_yield: mergeField(e.summary?.macro, i.summary?.macro, 'india_10y_yield'),
        usd_inr: mergeField(e.summary?.macro, i.summary?.macro, 'usd_inr'),
        gold: mergeField(e.summary?.macro, i.summary?.macro, 'gold'),
        india_vix: mergeField(e.summary?.macro, i.summary?.macro, 'india_vix'),
        us_10y_yield: mergeField(e.summary?.macro, i.summary?.macro, 'us_10y_yield'),
      },
      global_indices: mergeScalar(e.summary?.global_indices, i.summary?.global_indices) ?? [],
    },
    triggers: {
      domestic: mergeScalar(e.triggers?.domestic, i.triggers?.domestic) ?? [],
      global: mergeScalar(e.triggers?.global, i.triggers?.global) ?? [],
    },
    deep_dive: {
      full_text: mergeField(e.deep_dive, i.deep_dive, 'full_text'),
      summary_takeaway: mergeField(e.deep_dive, i.deep_dive, 'summary_takeaway'),
    },
    outlook: {
      base_case: mergeField(e.outlook, i.outlook, 'base_case'),
      scenarios: mergeScalar(e.outlook?.scenarios, i.outlook?.scenarios) ?? [],
      support_levels: mergeScalar(e.outlook?.support_levels, i.outlook?.support_levels) ?? [],
      resistance_levels: mergeScalar(e.outlook?.resistance_levels, i.outlook?.resistance_levels) ?? [],
      key_watch: mergeScalar(e.outlook?.key_watch, i.outlook?.key_watch) ?? [],
    },
    prediction_result: e.prediction_result,
    admin_notes: e.admin_notes ?? i.admin_notes ?? null,
  };
}

const isNew = !existing;
const finalBriefing = isNew ? incoming : mergeBriefing(existing, incoming);

return [{ json: { briefing: finalBriefing, date, sha, isNew } }];

// Prepare GitHub API call — encode the final (new or merged) briefing as base64
const { briefing, date, sha, isNew } = items[0].json;
const content = Buffer.from(JSON.stringify(briefing, null, 2)).toString('base64');
return [{ json: { date, content, path: `data/briefings/${date}.json`, sha, isNew } }];

// Commit (create) or update-in-place (merge) the briefing file via GitHub API
const { date, content, path, sha, isNew } = items[0].json;

const body = {
  message: isNew ? `Publish briefing for ${date}` : `Merge briefing update for ${date}`,
  content,
  branch: 'main'
};
if (sha) body.sha = sha;

return [{ json: { date, path, isNew, body: JSON.stringify(body) } }];

